scwin.sbm_retrieve_submitdone = async function (e) {
    var rowcnt = ds_popup.getRowCount();

    txt_totalRows.setValue(rowcnt);

	if (scwin.strExistTF == "T") {
        $c.win.closePopup(rowcnt);
		return ;
	} else {
		if (rowcnt == 1) {
            //	scwin.f_rtnValue(); 	   
            ds_popup.setCellData(0, "sendChk", "T"); 
            scwin.f_rtnValue();		
		}

		if (rowcnt == 0	) {
			await $c.gus.cfAlertMsg(MSG_CM_WRN_002);	// 조회결과가 존재하지 않습니다
			ed_Condition1.setValue("");
			ed_Condition2.setValue("");
			ed_Condition2.focus();
			return; 
		}
	}
	ds_popup.setRowPosition(0);
	gr_popup.focus();
	scwin.load_cnt = 1;
};

